  ('promotion-64311456-moex-00050', 'promotion-64311456', 'promotion-64311456-moex-112-d44949ff', 'sub-promotion-64311456-03', NULL, 'essay', '依兒童及少年福利與權益保障法第 56 條規定，兒少受到不當對待或嚴
重疏忽，致未能獲得適當養育及照顧時，縣市主管機關應予保護、安置，
必要時得進行緊急安置。然而，根據我國聯合國兒童權利公約首次國家
報告之國際審查結論性意見顯示，目前接受機構安置之兒少比率偏高，
請說明造成此種現象之原因為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:36+00:00", "source_pdf_sha1": "1fa6160c4b58", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "106", "s": "0802", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會福利服務", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會行政"}'::jsonb, NULL),
